import axios from 'axios';

const API = axios.create({ baseURL: process.env.REACT_APP_API_URL || '/api' });

// Attach token to every request
API.interceptors.request.use((config) => {
  const token = localStorage.getItem('ncc_token');
  if (token) config.headers.Authorization = `Bearer ${token}`;
  return config;
});

/* ── Songs ─────────────────────────────────────────────────────── */
export const fetchSongs = (params) => API.get('/songs', { params }).then((r) => r.data);
export const fetchSong  = (id)     => API.get(`/songs/${id}`).then((r) => r.data);
export const createSong = (data)   => API.post('/songs', data).then((r) => r.data);
export const updateSong = (id, data) => API.put(`/songs/${id}`, data).then((r) => r.data);
export const deleteSong = (id)     => API.delete(`/songs/${id}`).then((r) => r.data);
export const bulkImport = (file)   => {
  const fd = new FormData(); fd.append('file', file);
  return API.post('/songs/bulk-import', fd, {
    headers: { 'Content-Type': 'multipart/form-data' },
  }).then((r) => r.data);
};
export const downloadTemplate = () =>
  API.get('/songs/export/template', { responseType: 'blob' }).then((r) => {
    const url = window.URL.createObjectURL(new Blob([r.data]));
    const a   = document.createElement('a'); a.href = url;
    a.download = 'songs_import_template.xlsx'; a.click();
  });

/* ── Auth ──────────────────────────────────────────────────────── */
export const login    = (data) => API.post('/auth/login', data).then((r) => r.data);
export const register = (data) => API.post('/auth/register', data).then((r) => r.data);
export const getMe    = ()     => API.get('/auth/me').then((r) => r.data);
